%%%%%%%% ICML 2026 EXAMPLE LATEX SUBMISSION FILE %%%%%%%%%%%%%%%%%
\documentclass{article}
% Recommended, but optional, packages for figures and better typesetting:
\usepackage{microtype}
\usepackage{graphicx}
\usepackage{subcaption}
\usepackage{booktabs} % for professional tables
\usepackage{makecell}
% 其他排版和表格需要的包
\usepackage{colortbl}
\usepackage{pifont}
\usepackage{makecell} % 用于表头换行
\usepackage{xcolor}   % 显式调用 xcolor 以支持颜色定义
\definecolor{rowgray}{gray}{0.9}
% 定义 cvprblue，防止 hyperref 报错 (这是 CVPR 的标准蓝，ICML 默认没有)
\definecolor{cvprblue}{rgb}{0.21,0.49,0.74}
% hyperref makes hyperlinks in the resulting PDF.
% If your build breaks (sometimes temporarily if a hyperlink spans a page)
% please comment out the following usepackage line and replace
% \usepackage{icml2026} with \usepackage[nohyperref]{icml2026} above.
% 注意：ICML 模板通常建议在调用 icml2026 之前调用 hyperref
\usepackage{hyperref}
% Attempt to make hyperref and algorithmic work together better:
\newcommand{\theHalgorithm}{\arabic{algorithm}}
% Use the following line for the initial blind version submitted for review:
\usepackage{icml2026}
% For preprint, use
% \usepackage[preprint]{icml2026}
% If accepted, instead use the following line for the camera-ready submission:
% \usepackage[accepted]{icml2026}
% 支持跨页长表格
\usepackage{longtable}
% 支持三线表画线 (\toprule, \midrule, \bottomrule)
\usepackage{booktabs}
% 支持标题设置 (\captionsetup)
\usepackage{caption}
% 修正表格列格式（可选，但推荐）
\usepackage{array}
% 数学相关包
\usepackage{amsmath}
\usepackage{amssymb}
\usepackage{mathtools}
\usepackage{amsthm}
\usepackage{multirow}
% 配置 hyperref 的详细参数 (通过 hypersetup 避免重复加载 package 导致的冲突)
\hypersetup{
    pagebackref,
    breaklinks,
    colorlinks,
    allcolors=cvprblue
}
% cleveref 必须在 hyperref 之后加载
\usepackage[capitalize,noabbrev]{cleveref}
%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
% THEOREMS
%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
\theoremstyle{plain}
\newtheorem{theorem}{Theorem}[section]
\newtheorem{proposition}[theorem]{Proposition}
\newtheorem{lemma}[theorem]{Lemma}
\newtheorem{corollary}[theorem]{Corollary}
\theoremstyle{definition}
\newtheorem{definition}[theorem]{Definition}
\newtheorem{assumption}[theorem]{Assumption}
\theoremstyle{remark}
\newtheorem{remark}[theorem]{Remark}
% Todonotes is useful during development; simply uncomment the next line
%    and comment out the line below the next line to turn off comments
%\usepackage[disable,textsize=tiny]{todonotes}
\usepackage[textsize=tiny]{todonotes}
% The \icmltitle you define below is probably too long as a header.
% Therefore, a short form for the running title is supplied here:
% 【修改】这里原本是模板文字，已改为你的论文标题
\icmltitlerunning{VideoChat-A2: Tree of Tools for Video Understanding}
\begin{document}
\twocolumn[
  \icmltitle{VideoChat-A2: Tree of Tools for Video Understanding via Multi-Step Reinforcement Learning}
  % It is OKAY to include author information, even for blind submissions: the
  % style file will automatically remove it for you unless you've provided
  % the [accepted] option to the icml2026 package.
  \icmlsetsymbol{equal}{*}
  \begin{icmlauthorlist}
    \icmlauthor{Firstname1 Lastname1}{equal,yyy}
    \icmlauthor{Firstname2 Lastname2}{equal,yyy,comp}
    \icmlauthor{Firstname3 Lastname3}{comp}
    \icmlauthor{Firstname4 Lastname4}{sch}
    \icmlauthor{Firstname5 Lastname5}{yyy}
    \icmlauthor{Firstname6 Lastname6}{sch,yyy,comp}
    \icmlauthor{Firstname7 Lastname7}{comp}
    \icmlauthor{Firstname8 Lastname8}{sch}
    \icmlauthor{Firstname9 Lastname9}{yyy,comp} % 注意：原代码有两个 Firstname8，我改为 9 了
  \end{icmlauthorlist}
  \icmlaffiliation{yyy}{Department of XXX, University of YYY, Location, Country}
  \icmlaffiliation{comp}{Company Name, Location, Country}
  \icmlaffiliation{sch}{School of ZZZ, Institute of WWW, Location, Country}
  \icmlcorrespondingauthor{Firstname1 Lastname1}{first1.last1@xxx.edu}
  \icmlcorrespondingauthor{Firstname2 Lastname2}{first2.last2@www.uk}
  % You may provide any keywords that you find helpful for describing your
  % paper; these are used to populate the "keywords" metadata in the PDF but
  % will not be shown in the document
  \icmlkeywords{Machine Learning, ICML, Video Understanding, Reinforcement Learning}
  \vskip 0.3in
]
% this must go after the closing bracket ] following \twocolumn[ ...
\printAffiliationsAndNotice{}  % no special notice (required even if empty)
% Or, if applicable, use the standard equal contribution text:
% \printAffiliationsAndNotice{\icmlEqualContribution}
\input{sec/0_abstract}    
\input{sec/1_intro}
\input{sec/2_Related}
\input{sec/3_Method}
\input{sec/4_Experiment}
\input{sec/5_Conclusion}
\nocite{langley00}
\bibliography{main}
\bibliographystyle{icml2026}
\input{sec/X_supp}
\end{document}
